return {
  json: {
    platform: 'youtube',
    title: $json.snippet?.title || '',
    views: Number($json.statistics?.viewCount || 0),
    likes: Number($json.statistics?.likeCount || 0),
    comments: Number($json.statistics?.commentCount || 0),
    channel: $json.snippet?.channelTitle || '',
    thumbnail: $json.snippet?.thumbnails?.maxres?.url || $json.snippet?.thumbnails?.high?.url || $json.snippet?.thumbnails?.default?.url || '',
    video_url: 'https://www.youtube.com/watch?v=' + ($json.id || ''),
    published_at: $json.snippet?.publishedAt || '',
  },
};

const views = Number($json.views || 0);
const likes = Number($json.likes || 0);
const comments = Number($json.comments || 0);

const engagementRate = views > 0 ? ((likes + comments) / views) * 100 : 0;

const publishedAt = $json.published_at ? new Date($json.published_at) : null;
const ageHours = publishedAt ? Math.max((Date.now() - publishedAt.getTime()) / 3600000, 1) : 24;
const velocity = views / ageHours;

// 0..100 blended score: 70% engagement + 30% freshness/velocity
const viralityScore = Math.min(
  100,
  Math.round((engagementRate * 0.7) + (Math.log10(velocity + 1) * 12 * 0.3))
);

return {
  json: {
    ...$json,
    engagement_rate: Number(engagementRate.toFixed(2)),
    virality_score: viralityScore,
  },
};
